// First, let's inspect the data structure
const inputData = $input.all();
console.log('Input structure:', JSON.stringify(inputData[0], null, 2));

// Access the data - adjust path based on your actual structure
let entities;
try {
  // Try different possible paths
  if (inputData[0].json && Array.isArray(inputData[0].json)) {
    entities = inputData[0].json[0]?.document?.entities;
  } else if (inputData[0].json?.document?.entities) {
    entities = inputData[0].json.document.entities;
  } else {
    throw new Error('Cannot find entities in the expected structure');
  }
} catch (error) {
  console.error('Error accessing entities:', error);
  return [];
}

if (!entities) {
  console.log('No entities found');
  return [];
}

const results = [];

entities.forEach((entity, index) => {
  // Check main entity for booleanValue: true
  if (entity.normalizedValue?.booleanValue === true) {
    results.push({
      type: entity.type,
      mentionText: entity.mentionText,
      confidence: entity.confidence,
      id: entity.id,
      source: 'main_entity'
    });
  }

  // Check properties for booleanValue: true
  if (entity.properties) {
    entity.properties.forEach(prop => {
      if (prop.normalizedValue?.booleanValue === true) {
        results.push({
          type: prop.type,
          parentType: entity.type,
          mentionText: prop.mentionText,
          confidence: prop.confidence,
          id: prop.id,
          source: 'property'
        });
      }
    });
  }
});

console.log('Found results:', results);

return results.map((item, index) => ({ json: item, index }));

